data.query:
mutation IssueRelationUpdate($id: String!, $input: IssueRelationUpdateInput!) {
    issueRelationUpdate(id: $id, input: $input) {
        success
        lastSyncId
        issueRelation {
            id
            type
            createdAt
            updatedAt
            archivedAt
            issue {
                id
            }
            relatedIssue {
                id
            }
        }
    }
}
